mapper.insert:
INSERT INTO stage_task (
    stage_name, stage_desc, start_time, end_time, deliverables,
    scoring_criteria, weight, teacher_id, status
) VALUES (
    #{stageName}, #{stageDesc}, #{startTime}, #{endTime}, #{deliverables},
    #{scoringCriteria}, #{weight}, #{teacherId}, #{status}
)

mapper.select:
SELECT st.stage_id, st.stage_name, st.stage_desc, st.start_time, st.end_time, st.deliverables, st.scoring_criteria, st.weight, st.teacher_id, t.teacher_name, CASE WHEN CURRENT_TIMESTAMP < st.start_time THEN 0 WHEN CURRENT_TIMESTAMP > st.end_time THEN 2 ELSE 1 END AS status, st.create_time FROM stage_task st LEFT JOIN teacher t ON st.teacher_id = t.teacher_id WHERE 1 = 1
AND st.stage_name LIKE CONCAT('%', #{keyword}, '%')
AND st.teacher_id = #{teacherId}
AND CASE WHEN CURRENT_TIMESTAMP < st.start_time THEN 0 WHEN CURRENT_TIMESTAMP > st.end_time THEN 2 ELSE 1 END = #{status}
ORDER BY st.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM stage_task st WHERE 1 = 1
AND st.stage_name LIKE CONCAT('%', #{keyword}, '%')
AND st.teacher_id = #{teacherId}
AND CASE WHEN CURRENT_TIMESTAMP < st.start_time THEN 0 WHEN CURRENT_TIMESTAMP > st.end_time THEN 2 ELSE 1 END = #{status}
